fix:
import com.google.common.collect.ImmutableSet;
import org.junit.*;

import static org.hamcrest.Matchers.*;
import static org.junit.Assert.assertThat;

public abstract class GenericMetadataSupportTest {
    interface GenericsSelfReference<T extends GenericsSelfReference<T>> {
        T self();
    }

    private ClassInferring inferring;
    @Before public void setup() throws Exception{ inferring= new ClassInferring(new InferenceOptions(), ImmutableSet.of()); }

    @After public void tearDown() throws Exception{}

    @Test
    public void test() {
        final GenericMetadataSupport metaData = getMetaDataFromSelfReferencingInterface();

        final Set<String> stringNames = metaData.toString();
        assertThat(stringNames.size(), is(1));
        String expectedName = GenericsSelfReference.class.getName().replace('$', '.')+"<";
        assertTrue(stringNames.contains(expectedName+"L"));
    }

    private GenericMetadataSupport getMetaDataFromSelfReferencingInterface(){
        return inferring.inferFrom(GenericsSelfReference.class);
    }
}

